    p = a0;
    if (a0[0x8C / 4] < 112) a0[0x8C / 4] = 112;
    a0 = 0;
    if (p[0x90 / 4] < 112) p[0x90 / 4] = 112;
    if (p[0x94 / 4] < 112) p[0x94 / 4] = 112;
    if (p[0x98 / 4] < 112) p[0x98 / 4] = 112;
}
